**Home.razor** — `Components/Pages/Home.razor` (Static SSR, replace existing)

```razor
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Westfield University — Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4">Welcome to the Course Catalog</h1>
    <p class="lead text-muted">Browse courses, explore departments, and enroll for the upcoming semester.</p>
    <a href="/courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
    <a href="/enroll" class="btn btn-outline-primary btn-lg">Enroll Now</a>
</div>

<section class="mb-5">
    <h2>Featured Courses</h2>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in Catalog.GetFeaturedCourses())
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@course.CourseCode</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                        <p class="card-text">@Truncate(course.Description, 120)</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="badge bg-secondary">@course.Credits Credits</span>
                            <a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section>
    <h2>Departments</h2>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3">
        @foreach (var dept in Catalog.GetDepartments())
        {
            <div class="col">
                <a href="/courses?department=@dept.Id" class="text-decoration-none">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@dept.Name</h5>
                            <p class="card-text text-muted">@dept.Code — @dept.Description</p>
                        </div>
                    </div>
                </a>
            </div>
        }
    </div>
</section>

@code {
    private string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}
```

**Courses.razor** — `Components/Pages/Courses.razor` (Interactive Server for live search/filter)

```razor
@page "/courses"
@rendermode InteractiveServer
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Course Catalog — Westfield University</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4 g-3">
    <div class="col-md-5">
        <input type="text" class="form-control" placeholder="Search courses..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartment">
            <option value="">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id">@dept.Name (@dept.Code)</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="selectedCredits">
            <option value="">Any Credits</option>
            <option value="1">1 Credit</option>
            <option value="2">2 Credits</option>
            <option value="3">3 Credits</option>
            <option value="4">4 Credits</option>
        </select>
    </div>
</div>

@{
    var results = Catalog.SearchCourses(searchTerm, 
        string.IsNullOrEmpty(selectedDepartment) ? null : int.Parse(selectedDepartment),
        string.IsNullOrEmpty(selectedCredits) ? null : int.Parse(selectedCredits));
}

<p class="text-muted">Showing @results.Count course(s)</p>

<div class="row row-cols-1 row-cols-md-2 g-4">
    @foreach (var course in results)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <h5 class="card-title mb-1">@course.CourseCode</h5>
                        <span class="badge bg-primary">@course.Credits cr.</span>
                    </div>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text small">@course.Schedule · @course.Location</p>
                    <p class="card-text small text-muted">Instructor: @course.Instructor.Name</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a>
                    <a href="/enroll?courseId=@course.Id" class="btn btn-sm btn-outline-success ms-2">Enroll</a>
                </div>
            </div>
        </div>
    }
</div>

@if (results.Count == 0)
{
    <div class="alert alert-info mt-3">No courses found matching your criteria. Try adjusting your search or filters.</div>
}

@code {
    private string searchTerm = "";
    private string selectedDepartment = "";
    private string selectedCredits = "";
}
```

**CourseDetail.razor** — `Components/Pages/CourseDetail.razor` (Static SSR)

```razor
@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found — Westfield University</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
    <a href="/courses" class="btn btn-primary">Back to Catalog</a>
}
else
{
    <PageTitle>@course.CourseCode @course.Title — Westfield University</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="/courses?department=@course.DepartmentId">@course.DepartmentName</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@course.CourseCode — @course.Title</h1>
            <p class="lead">@course.Description</p>

            <h3 class="mt-4">Course Details</h3>
            <table class="table">
                <tbody>
                    <tr><th style="width:200px">Course Code</th><td>@course.CourseCode</td></tr>
                    <tr><th>Credits</th><td>@course.Credits</td></tr>
                    <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                    <tr><th>Location</th><td>@course.Location</td></tr>
                    <tr><th>Department</th><td>@course.DepartmentName</td></tr>
                    <tr>
                        <th>Enrollment</th>
                        <td>@course.CurrentEnrollment / @course.MaxEnrollment
                            @if (course.CurrentEnrollment >= course.MaxEnrollment)
                            {
                                <span class="badge bg-danger ms-2">Full</span>
                            }
                            else
                            {
                                <span class="badge bg-success ms-2">Open</span>
                            }
                        </td>
                    </tr>
                </tbody>
            </table>

            <a href="/enroll?courseId=@course.Id" class="btn btn-success">Enroll in This Course</a>
            <a href="/courses" class="btn btn-outline-secondary ms-2">Back to Catalog</a>
        </div>

        <div class="col-lg-4 mt-4 mt-lg-0">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Instructor</h5></div>
                <div class="card-body">
                    <h5>@course.Instructor.Name</h5>
                    <p class="text-muted mb-1">@course.Instructor.Title</p>
                    <p>@course.Instructor.Bio</p>
                    <ul class="list-unstyled mb-0">
                        <li>📧 @course.Instructor.Email</li>
                        <li>🏢 @course.Instructor.Office</li>
                    </ul>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}
```

**Enroll.razor** — `Components/Pages/Enroll.razor` (Static SSR with HTML form)

```razor
@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog
@inject NavigationManager Navigation

<PageTitle>Enroll — Westfield University</PageTitle>

<h1>Enrollment Request</h1>
<p class="text-muted">Fill out the form below to submit an enrollment request.</p>

<div class="row">
    <div class="col-lg-7">
        <EditForm Model="request" method="post" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name</label>
                <InputText id="studentName" class="form-control" @bind-Value="request.StudentName" />
                <ValidationMessage For="() => request.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" placeholder="e.g., S1234567" @bind-Value="request.StudentId" />
                <ValidationMessage For="() => request.StudentId" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <InputSelect id="courseId" class="form-select" @bind-Value="request.CourseId">
                    <option value="0">— Select a course —</option>
                    @foreach (var course in Catalog.GetCourses())
                    {
                        <option value="@course.Id">@course.CourseCode — @course.Title (@course.Credits cr.)</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => request.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
        </EditForm>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest request { get; set; } = new();

    [SupplyParameterFromQuery]
    private int? courseId { get; set; }

    protected override void OnInitialized()
    {
        if (courseId.HasValue && request.CourseId == 0)
        {
            request.CourseId = courseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Catalog.SubmitEnrollment(request);
        Navigation.NavigateTo($"/enroll/confirmation?courseId={request.CourseId}");
    }
}
```

